&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;XX&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;CH&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;INCR&lt;/span&gt;] &lt;span class=&#34;title&#34;&gt;score&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;score&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt; ...]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Add&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;one&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;more&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;update&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;its&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;score&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;it&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;already&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;exists&lt;/span&gt;(向已排序的集合中添加一个或多个成员，如果已经存在，则更新其分数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZCARD&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Get&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;number&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;(获取已排序集合中的成员数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZCOUNT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;min&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;max&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Count&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;within&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;values&lt;/span&gt;(在给定值内对排序集合中的成员进行计数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZINCRBY&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;increment&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Increment&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;score&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;(递增排序集合中成员的分数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZINTERSTORE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;destination&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;numkeys&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; ...] [&lt;span class=&#34;title&#34;&gt;WEIGHTS&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;weight&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;AGGREGATE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;SUM&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;MIN&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;MAX&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Intersect&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sets&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;store&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;resulting&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;(交叉多个排序集，并将结果排序集存储到一个新键中)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZLEXCOUNT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;min&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;max&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt